           text.starts_with("DELETE ") || 
           text.starts_with("HEAD ") || 
           text.starts_with("OPTIONS ") || 
           text.starts_with("CONNECT ") || 
           text.starts_with("PATCH ") {
            debug!("POSIX: Detected HTTP protocol");
