{"content":"//! ModelMux - OpenAI-compatible LLM proxy with intelligent routing
//!
//! Features:
//! - `/provider/model` routing (e.g., `/anthropic/claude-3-5-sonnet`)
//! - QUIC/h3 support on single UDP port
//! - Intelligent ranker with pluggable trait
//! - Encrypted SQLite key vault (shared with cc-switch)
//! - Per-key quota management
//! - Radio-aware egress (LiteBike integration)

mod key_vault;
mod ranker;
mod router;
mod quic_server;
mod handlers;
mod types;

use anyhow::Result;
use clap::Parser;
use log::{info, error};
use std::net::SocketAddr;
use std::sync::Arc;

#[derive(Parser, Debug)]
#[command(author, version, about, long_about = None)]
struct Args {
    /// Port to listen on (default: 8888)
    #[arg(short, long, default_value_t = 8888)]
    port: u16,

    /// Protocol: quic, tcp, or auto (default: auto)
    #[arg(short, long, default_value = "auto")]
    proto: String,

    /// Config file path (default: ~/.cc-switch/muxer.json)
    #[arg(short, long)]
    config: Option<String>,

    /// SQLite database path (default: ~/.cc-switch/cc-switch.db)
    #[arg(long)]
    db_path: Option<String>,

    /// Enable verbose logging
    #[arg(short, long)]
    verbose: bool,
}

#[tokio::main]
async fn main() -> Result<()> {
    let args = Args::parse();

    // Initialize logging
    let log_level = if args.verbose { "debug" } else { "info" };
    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or(log_level))
        .init();

    info!("🚀 ModelMux starting...");
    info!("  Port: {}", args.port);
    info!("  Protocol: {}", args.proto);
    info!("  Config: {:?}", args.config);
    info!("  Database: {:?}", args.db_path);

    // Initialize key vault (encrypted SQLite)
    let db_path = args.db_path.unwrap_or_else(|| {
        dirs::home_dir()
            .map(|h| h.join(".cc-switch").join("cc-switch.db"))
            .unwrap_or_else(|| "cc-switch.db".into())
    });

    let key_vault = Arc::new(key_vault::KeyVault::open(&db_path)?);
    info!("  Key vault: {}", db_path.display());

    // Initialize ranker
    let ranker = Arc::new(ranker::DefaultRanker::new());

    // Start server based on protocol
    let addr = SocketAddr::from(([0, 0, 0, 0], args.port));

    match args.proto.as_str() {
        "quic" => {
            info!("  Starting QUIC/h3 server...");
            quic_server::start_quic_server(addr, key_vault, ranker).await?;
        }
        "tcp" => {
            info!("  Starting TCP/HTTP server...");
            router::start_tcp_server(addr, key_vault, ranker).await?;
        }
        "auto" => {
            info!("  Starting auto protocol server (QUIC + TCP fallback)...");
            // Start both QUIC and TCP, QUIC on primary port, TCP on port+1
            let quic_addr = addr;
            let tcp_addr = SocketAddr::from(([0, 0, 0, 0], args.port + 1));

            tokio::select! {
                result = quic_server::start_quic_server(quic_addr, key_vault.clone(), ranker.clone()) => {
                    if let Err(e) = result {
                        error!("QUIC server error: {}", e);
                    }
                }
                result = router::start_tcp_server(tcp_addr, key_vault, ranker) => {
                    if let Err(e) = result {
                        error!("TCP server error: {}", e);
                    }
                }
            }
        }
        _ => {
            anyhow::bail!("Unknown protocol: {}. Use 'quic', 'tcp', or 'auto'.", args.proto);
        }
    }

    Ok(())
}
