{"content":"//! QUIC/h3 server implementation with 0-RTT and connection migration
//!
//! Features:
//! - Single UDP port for HTTP/3 (QUIC)
//! - 0-RTT session resumption (faster reconnections)
//! - Connection migration (survive IP changes)
//! - Automatic fallback to HTTP/2 + HTTP/1.1

use crate::acl_vault::AclKeyVault;
use crate::ranker::Ranker;
use crate::router::{AppState, start_tcp_server};
use anyhow::{Result, Context};
use h3::server::Connection;
use h3_quinn::quinn::{self, ServerConfig, crypto::rustls::QuicServerConfig};
use log::{info, error, debug, warn};
use rustls::{pki_types::{CertificateDer, PrivateKeyDer}, ServerConfig as TlsServerConfig};
use std::net::SocketAddr;
use std::sync::Arc;
use std::fs::File;
use std::io::BufReader;
use std::path::Path;

/// QUIC server configuration
#[derive(Debug, Clone)]
pub struct QuicConfig {
    /// Port to listen on
    pub port: u16,
    /// TLS certificate path (PEM format)
    pub cert_path: String,
    /// TLS private key path (PEM format)
    pub key_path: String,
    /// Enable 0-RTT session resumption
    pub enable_0rtt: bool,
    /// Connection idle timeout (seconds)
    pub idle_timeout: u64,
    /// Max concurrent bidirectional streams
    pub max_concurrent_streams: u64,
}

impl Default for QuicConfig {
    fn default() -> Self {
        Self {
            port: 8888,
            cert_path: "~/.cc-switch/certs/server.crt".to_string(),
            key_path: "~/.cc-switch/certs/server.key".to_string(),
            enable_0rtt: true,
            idle_timeout: 30,
            max_concurrent_streams: 100,
        }
    }
}

/// Generate self-signed certificate for development
pub fn generate_self_signed_cert(cert_path: &str, key_path: &str) -> Result<()> {
    use rcgen::{Certificate, CertificateParams, DistinguishedName};
    use std::fs;

    info!("Generating self-signed certificate for development...");

    // Create certificate directory
    if let Some(parent) = Path::new(cert_path).parent() {
        fs::create_dir_all(parent)?;
    }

    // Generate certificate
    let mut params = CertificateParams::default();
    let mut dn = DistinguishedName::new();
    dn.push(rcgen::DnType::CommonName, "localhost");
    dn.push(rcgen::DnType::OrganizationName, "ModelMux Development");
    params.distinguished_name = dn;
    params.subject_alt_names = vec![
        rcgen::SanType::DnsName("localhost".to_string()),
        rcgen::SanType::IpAddress(std::net::IpAddr::V4(std::net::Ipv4Addr::new(127, 0, 0, 1))),
    ];

    let cert = Certificate::from_params(params)?;

    // Write certificate
    fs::write(cert_path, cert.serialize_pem()?)?;

    // Write private key
    fs::write(key_path, cert.serialize_private_key_pem())?;

    // Set secure permissions
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        fs::set_permissions(key_path, fs::Permissions::from_mode(0o600))?;
    }

    info!("  Certificate: {}", cert_path);
    info!("  Private key: {}", key_path);

    Ok(())
}

/// Load TLS configuration from files
fn load_tls_config(cert_path: &str, key_path: &str) -> Result<TlsServerConfig> {
    // Expand tilde
    let cert_path = shellexpand::tilde(cert_path).to_string();
    let key_path = shellexpand::tilde(key_path).to_string();

    // Check if files exist, generate self-signed if not
    if !Path::new(&cert_path).exists() || !Path::new(&key_path).exists() {
        generate_self_signed_cert(&cert_path, &key_path)?;
    }

    // Load certificate
    let cert_file = File::open(&cert_path)
        .context(format!("Failed to open certificate file: {}", cert_path))?;
    let mut cert_reader = BufReader::new(cert_file);
    let certs: Vec<CertificateDer> = rustls_pemfile::certs(&mut cert_reader)
        .collect::<Result<Vec<_>, _>>()?;

    // Load private key
    let key_file = File::open(&key_path)
        .context(format!("Failed to open key file: {}", key_path))?;
    let mut key_reader = BufReader::new(key_file);
    let key = rustls_pemfile::private_key(&mut key_reader)?
        .context("No private key found")?;

    // Build TLS config
    let mut tls_config = TlsServerConfig::builder()
        .with_no_client_auth()
        .with_single_cert(certs, key)?;

    // Set ALPN protocols (HTTP/3)
    tls_config.alpn_protocols = vec![b"h3".to_vec()];

    Ok(tls_config)
}

/// Build QUIC server configuration
fn build_quic_server_config(tls_config: TlsServerConfig, quic_config: &QuicConfig) -> Result<ServerConfig> {
    let mut transport_config = quinn::TransportConfig::default();

    // Connection idle timeout
    transport_config.max_idle_timeout(Some(
        quinn::VarInt::from(quic_config.idle_timeout * 1000).into()
    ));

    // Max concurrent streams
    transport_config.max_concurrent_bidi_streams(quic_config.max_concurrent_streams.into());

    // Connection migration (survive IP changes)
    transport_config.migration(true);

    // 0-RTT session resumption
    if quic_config.enable_0rtt {
        transport_config.send_grease(true);
        transport_config.keep_alive_interval(Some(std::time::Duration::from_secs(5)));
    }

    // Build QUIC config
    let crypto = QuicServerConfig::try_from(tls_config)?;
    let mut server_config = ServerConfig::with_crypto(Arc::new(crypto));
    server_config.transport_config(Arc::new(transport_config));

    Ok(server_config)
}

/// Start QUIC/h3 server
pub async fn start_quic_server(
    addr: SocketAddr,
    key_vault: Arc<AclKeyVault>,
    ranker: Arc<dyn Ranker>,
    quic_config: Option<QuicConfig>,
) -> Result<()> {
    let quic_config = quic_config.unwrap_or_default();

    // Load TLS configuration
    let tls_config = load_tls_config(&quic_config.cert_path, &quic_config.key_path)?;

    // Build QUIC server configuration
    let server_config = build_quic_server_config(tls_config, &quic_config)?;

    // Create QUIC endpoint
    let endpoint = quinn::Endpoint::server(server_config, addr)?;

    info!("  QUIC/h3 server listening on {} (UDP)", addr);
    info!("  0-RTT: {}", if quic_config.enable_0rtt { "enabled" } else { "disabled" });
    info!("  Connection migration: enabled");
    info!("  Max concurrent streams: {}", quic_config.max_concurrent_streams);

    // Accept connections
    while let Some(conn) = endpoint.accept().await {
        let connection = match conn.await {
            Ok(c) => c,
            Err(e) => {
                error!("Connection failed: {}", e);
                continue;
            }
        };

        let connection_id = connection.stable_id();
        debug!("New QUIC connection: {}", connection_id);

        // Clone state for connection handler
        let state = AppState {
            key_vault: key_vault.clone(),
            ranker: ranker.clone(),
        };

        // Spawn connection handler
        tokio::spawn(async move {
            if let Err(e) = handle_quic_connection(connection, state).await {
                error!("Connection {} error: {}", connection_id, e);
            }
        });
    }

    Ok(())
}

/// Handle a single QUIC connection
async fn handle_quic_connection(
    connection: Connection<h3_quinn::Connection, bytes::Bytes>,
    state: AppState,
) -> Result<()> {
    let connection_id = connection.stable_id();

    // Accept bidirectional streams
    let mut connection = connection;
    while let Some(stream) = connection.accept_bi().await {
        match stream {
            Ok((send, recv)) => {
                debug!("New stream on connection {}", connection_id);

                // Spawn stream handler
                let state = state.clone();
                tokio::spawn(async move {
                    if let Err(e) = crate::h3_handler::handle_h3_stream(send, recv, state).await {
                        error!("Stream error on connection {}: {}", connection_id, e);
                    }
                });
            }
            Err(e) => {
                error!("Failed to accept stream on connection {}: {}", connection_id, e);
            }
        }
    }

    debug!("Connection {} closed", connection_id);
    Ok(())
}

/// Start auto protocol server (QUIC + TCP fallback)
pub async fn start_auto_server(
    addr: SocketAddr,
    key_vault: Arc<AclKeyVault>,
    ranker: Arc<dyn Ranker>,
    quic_config: Option<QuicConfig>,
) -> Result<()> {
    let quic_config = quic_config.unwrap_or_default();

    // Start QUIC on primary port
    let quic_addr = addr;

    // Start TCP on port + 1 (fallback)
    let tcp_addr = SocketAddr::from(([0, 0, 0, 0], addr.port() + 1));

    info!("Starting auto protocol server...");
    info!("  QUIC/h3: {} (UDP)", quic_addr);
    info!("  TCP/HTTP: {} (TCP)", tcp_addr);

    // Spawn QUIC server
    let quic_key_vault = key_vault.clone();
    let quic_ranker = ranker.clone();
    let quic_config_clone = quic_config.clone();
    let quic_handle = tokio::spawn(async move {
        start_quic_server(quic_addr, quic_key_vault, quic_ranker, Some(quic_config_clone)).await
    });

    // Spawn TCP server
    let tcp_key_vault = key_vault;
    let tcp_ranker = ranker;
    let tcp_handle = tokio::spawn(async move {
        start_tcp_server(tcp_addr, tcp_key_vault, tcp_ranker).await
    });

    // Wait for either to fail
    tokio::select! {
        result = quic_handle => {
            if let Err(e) = result? {
                error!("QUIC server failed: {}", e);
            }
        }
        result = tcp_handle => {
            if let Err(e) = result? {
                error!("TCP server failed: {}", e);
            }
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::tempdir;

    #[test]
    fn test_generate_self_signed_cert() -> Result<()> {
        let dir = tempdir()?;
        let cert_path = dir.path().join("server.crt");
        let key_path = dir.path().join("server.key");

