{"content":"//! HTTP/3 stream handler
//!
//! Handles individual HTTP/3 streams within a QUIC connection

use crate::router::AppState;
use anyhow::Result;
use bytes::Bytes;
use h3::{quic::BidiStream, server::RequestStream};
use http::{Request, Response, StatusCode};
use log::{debug, error};
use serde_json::json;

/// Handle a single HTTP/3 stream
pub async fn handle_h3_stream<S>(
    send: S,
    recv: S::RecvStream,
    state: AppState,
) -> Result<()>
where
    S: BidiStream<Bytes>,
{
    // Create HTTP/3 request stream
    let mut stream = RequestStream::new(send, recv);

    // Read request
    let request = match stream.recv_request().await {
        Ok(Some(req)) => req,
        Ok(None) => return Ok(()), // End of stream
        Err(e) => {
            error!("Failed to receive request: {}", e);
            return Err(e.into());
        }
    };

    debug!("HTTP/3 request: {} {}", request.method(), request.uri());

    // Route request
    let response = route_request(request, state).await;

    // Send response
    if let Err(e) = stream.send_response(response).await {
        error!("Failed to send response: {}", e);
        return Err(e.into());
    }

    Ok(())
}

/// Route HTTP/3 request to appropriate handler
async fn route_request(request: Request<()>, state: AppState) -> Response<()> {
    let method = request.method();
    let path = request.uri().path();

    debug!("Routing: {} {}", method, path);

    match (method.as_str(), path) {
        ("GET", "/health") => health_check(),
        ("GET", "/v1/models") => handle_models(state).await,
        ("POST", "/v1/chat/completions") => handle_chat_completions(request, state).await,
        ("POST", "/v1/embeddings") => handle_embeddings(request, state).await,
        _ => not_found(),
    }
}

/// Health check endpoint
fn health_check() -> Response<()> {
    let body = json!({
        "status": "healthy",
        "protocol": "HTTP/3 (QUIC)",
        "timestamp": chrono::Utc::now().to_rfc3339(),
    });

    http::Response::builder()
        .status(StatusCode::OK)
        .header("content-type", "application/json")
        .body(())
        .unwrap()
}

/// Handle /v1/models
async fn handle_models(state: AppState) -> Response<()> {
    let providers = state.key_vault.list_providers();

    let models: Vec<_> = providers.iter()
        .map(|provider| json!({
            "id": format!("{}/{}", provider, "default-model"),
            "object": "model",
            "created": chrono::Utc::now().timestamp(),
            "owned_by": provider,
        }))
        .collect();

    let body = json!({
        "object": "list",
        "data": models,
    });

    http::Response::builder()
        .status(StatusCode::OK)
        .header("content-type", "application/json")
        .body(())
        .unwrap()
}

/// Handle /v1/chat/completions
async fn handle_chat_completions(request: Request<()>, state: AppState) -> Response<()> {
    // TODO: Implement full chat completions handler for HTTP/3
    // For now, return placeholder

    let body = json!({
