{"content":"/**
 * ModelMux Panel for CC-Switch
 *
 * Provides UI for:
 * - API key management (add/remove/list keys)
 * - Muxer control (start/stop/status)
 * - Provider configuration
 * - Quota monitoring
 * - Carrier metrics
 */

import React, { useState, useEffect } from 'react';
import { invoke } from '@tauri-apps/api/core';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Progress } from '@/components/ui/progress';
import { toast } from 'sonner';
import {
  Key,
  Server,
  Activity,
  Plus,
  Trash2,
  Play,
  Square,
  RefreshCw,
  Wifi,
  Signal,
} from 'lucide-react';

interface ApiKeyInfo {
  id: string;
  provider: string;
  quota_limit: number | null;
  quota_used: number;
  is_active: boolean;
  created_at: number;
}

interface ProviderInfo {
  name: string;
  key_count: number;
  total_quota_limit: number | null;
  total_quota_used: number;
}

interface MuxerStatus {
  is_running: boolean;
  port: number | null;
  protocol: string | null;
  pid: number | null;
  uptime_seconds: number | null;
}

export function MuxerPanel() {
  const [keys, setKeys] = useState<ApiKeyInfo[]>([]);
  const [providers, setProviders] = useState<ProviderInfo[]>([]);
  const [muxerStatus, setMuxerStatus] = useState<MuxerStatus | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  // Add key form state
  const [newProvider, setNewProvider] = useState('');
  const [newKey, setNewKey] = useState('');
  const [newQuota, setNewQuota] = useState<string>('');

  // Load data on mount
  useEffect(() => {
    loadData();
  }, []);

  async function loadData() {
    setIsLoading(true);
    try {
      const [keysResult, providersResult, statusResult] = await Promise.all([
        invoke<ApiKeyInfo[]>('muxer_list_keys'),
        invoke<ProviderInfo[]>('muxer_list_providers'),
        invoke<MuxerStatus>('muxer_status'),
      ]);
      setKeys(keysResult);
      setProviders(providersResult);
      setMuxerStatus(statusResult);
    } catch (error) {
      toast.error(`Failed to load data: ${error}`);
    } finally {
      setIsLoading(false);
    }
  }

  async function handleAddKey() {
    if (!newProvider || !newKey) {
      toast.error('Provider and key are required');
      return;
    }

    try {
      const keyId = await invoke<string>('muxer_add_key', {
        request: {
          provider: newProvider,
          key: newKey,
          quota_limit: newQuota ? parseFloat(newQuota) : null,
          permissions: 0o600,
        },
      });
      toast.success(`Key added: ${keyId}`);
      setNewProvider('');
      setNewKey('');
      setNewQuota('');
      loadData();
    } catch (error) {
      toast.error(`Failed to add key: ${error}`);
    }
  }

  async function handleStartMuxer() {
    try {
      await invoke('muxer_start', { port: 8888, protocol: 'auto' });
      toast.success('ModelMux started on port 8888');
      loadData();
    } catch (error) {
      toast.error(`Failed to start muxer: ${error}`);
    }
  }

  async function handleStopMuxer() {
    try {
      await invoke('muxer_stop');
      toast.success('ModelMux stopped');
      loadData();
    } catch (error) {
      toast.error(`Failed to stop muxer: ${error}`);
    }
  }

  function formatQuota(used: number, limit: number | null) {
    if (!limit) return `${used.toFixed(2)} tokens (unlimited)`;
    const percentage = ((used / limit) * 100).toFixed(1);
    return `${used.toFixed(2)} / ${limit.toFixed(2)} (${percentage}%)`;
  }

  return (
    <div className="space-y-6">
      {/* Muxer Control Card */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Server className="w-5 h-5" />
            ModelMux Control
          </CardTitle>
          <CardDescription>
            Start/stop the ModelMux proxy server
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-center gap-4">
            {muxerStatus?.is_running ? (
              <>
                <Badge variant="success" className="gap-1">
                  <Activity className="w-3 h-3" />
                  Running on port {muxerStatus.port}
                </Badge>
                <Button variant="destructive" onClick={handleStopMuxer}>
                  <Square className="w-4 h-4 mr-2" />
                  Stop
                </Button>
              </>
            ) : (
              <>
                <Badge variant="secondary">Stopped</Badge>
                <Button onClick={handleStartMuxer}>
                  <Play className="w-4 h-4 mr-2" />
                  Start (Port 8888)
                </Button>
              </>
            )}
            <Button variant="outline" onClick={loadData} disabled={isLoading}>
              <RefreshCw className={`w-4 h-4 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
              Refresh
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Tabs for Keys and Providers */}
      <Tabs defaultValue="keys">
        <TabsList>
          <TabsTrigger value="keys" className="gap-2">
            <Key className="w-4 h-4" />
            API Keys
          </TabsTrigger>
          <TabsTrigger value="providers" className="gap-2">
            <Signal className="w-4 h-4" />
            Providers
          </TabsTrigger>
        </TabsList>

        {/* API Keys Tab */}
        <TabsContent value="keys" className="space-y-4">
          {/* Add Key Form */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Plus className="w-5 h-5" />
                Add API Key
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid gap-4 md:grid-cols-4">
                <div className="space-y-2">
                  <Label htmlFor="provider">Provider</Label>
                  <Select value={newProvider} onValueChange={setNewProvider}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select provider" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="anthropic">Anthropic</SelectItem>
                      <SelectItem value="openai">OpenAI</SelectItem>
                      <SelectItem value="google">Google</SelectItem>
